const SCHEMA = {
  type: 'object',
  required: ['file', 'built', 'summary'],
  properties: {
    file: { type: 'string' },
    built: { type: 'boolean' },
    title: { type: 'string' },
    summary: { type: 'string' },
    keyFeatures: { type: 'array', items: { type: 'string' } },
    risks: { type: 'string' },
  },
}

phase('Build')
const results = await parallel(TASKS.map((t) => () => agent(t.prompt, { label: `build:${t.file}`, phase: 'Build', schema: SCHEMA })))
const ok = results.filter(Boolean)
log(`Built ${ok.length}/${TASKS.length} apps`)
return ok
